// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UxExecutionStep) predicate.UxExecutionStep {
	return predicate.UxExecutionStep(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UxExecutionStep) predicate.UxExecutionStep {
	return predicate.UxExecutionStep(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UxExecutionStep) predicate.UxExecutionStep {
	return predicate.UxExecutionStep(sql.NotPredicates(p))
}
